import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/blog.md","filePath":"my/Other/blog.md","lastUpdated":1781962217000}'),n={name:"my/Other/blog.md"};function r(c,e,d,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature က သင့် ImgBed site ထဲ blog page သီးခြားတစ်ခုထည့်ပေးပါတယ်။</p><p>enable လုပ်ပြီးနောက် visitors တွေဖွင့်နိုင်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>ဒီ blog က open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project ကိုအခြေခံပြီး ပြင်ဆင်ထားတာပါ။ ImgBed က Vue နဲ့ integrate လုပ်ထားလို့ image hosting site ရဲ့အစိတ်အပိုင်းအဖြစ်အလုပ်လုပ်ပါတယ်။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>Blog settings က ဒီနေရာမှာရှိပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Enable</code> ကို on လုပ်ပါ။</li><li>blog configuration သိမ်းမယ့် GitHub account ကိုရွေးပါ။</li><li><code>Update Blog</code> ကိုနှိပ်ပါ။</li><li>success message ကိုစောင့်ပါ။</li><li>blog ကြည့်ရန် <code>https://your-domain.com/blog/</code> ကိုဖွင့်ပါ။</li></ol><p>ပထမဆုံးအသုံးပြုတဲ့အခါ ImgBed ကရွေးထားတဲ့ account အောက်မှာ private GitHub repository တစ်ခုပြင်ဆင်ပါမယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>ဒီ repository က blog settings နဲ့ article content ကိုသိမ်းပါတယ်။</p><h2 id="posts-ရေးခြင်း" tabindex="-1">Posts ရေးခြင်း <a class="header-anchor" href="#posts-ရေးခြင်း" aria-label="Permalink to &quot;Posts ရေးခြင်း&quot;">​</a></h2><p>blog posts တွေကို သင့် private GitHub repository ထဲမှာ edit လုပ်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>ပုံမှန် workflow:</p><ol><li>GitHub ကိုဖွင့်ပါ။</li><li>private <code>imgbed-blog-config</code> repository ထဲဝင်ပါ။</li><li>post files edit သို့မဟုတ် add လုပ်ပါ။</li><li>changes commit လုပ်ပါ။</li><li>ImgBed admin panel ကိုပြန်သွားပြီး <code>Update Blog</code> ကိုနှိပ်ပါ၊ သို့မဟုတ် blog homepage ရဲ့ဘယ်ဘက်အပေါ် logo ကိုသုံးကြိမ်နှိပ်ပြီး blog update trigger လုပ်ပါ။</li></ol><p><code>Update Blog</code> က သင်ရေးထားတဲ့ content ကို overwrite မလုပ်ပါ။ လိုအပ်ရင် repository initialize လုပ်ပြီး blog cache refresh လုပ်ပါတယ်။</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog က post lists, categories, tags, archives, search, dark mode, language switching စတဲ့ blog features တွေကို support လုပ်ပါတယ်။</p><p>comments နဲ့ visit statistics လည်း support လုပ်ပါတယ်။</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>comments တွေက posts အောက်မှာပေါ်ပါတယ်။ visitors တွေက avatar, nickname, email, comment content ပို့နိုင်ပါတယ်။</p><p>visit statistics က post views နဲ့ site visits ကိုပြပြီး blog traffic နားလည်ဖို့ကူညီပါတယ်။</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog က အမြဲ <code>/blog/</code> အောက်မှာ serve လုပ်ပါတယ်။</p><p>ဥပမာ သင့် ImgBed domain က:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>blog URL က:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>blog disabled ဖြစ်ပြီးနောက် visitors တွေ blog page ကို access မလုပ်နိုင်တော့ပါ။</p>',34)])])}const f=i(n,[["render",r]]);export{v as __pageData,f as default};
